package main

import (
	"errors"
	"fmt"
	"html"
	"strings"
)

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if fromAddr == "" || toAddr == "" {
		return "", errors.New("fromAddr and toAddr must not be empty")
	}

	// Escape HTML special characters in user-provided content
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Convert newlines to <br> tags in content
	escapedContent = strings.ReplaceAll(escapedContent, "\n", "<br>")

	// Build email headers
	headers := []string{
		"From: " + fromAddr,
		"To: " + toAddr,
		"Subject: " + subject,
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=\"UTF-8\"",
		"", // Empty line to separate headers and body
	}

	// Build HTML email body
	htmlBody := fmt.Sprintf(`
<html>
<body>
	<h2>User Feedback Received</h2>
	<table border="0" cellpadding="5" cellspacing="0" width="100%%">
		<tr><td width="100"><b>Username:</b></td><td>%s</td></tr>
		<tr><td><b>Subject:</b></td><td>%s</td></tr>
		<tr><td valign="top"><b>Content:</b></td><td>%s</td></tr>
	</table>
</body>
</html>
`, escapedUserName, escapedSubject, escapedContent)

	// Combine headers and body
	emailBody = strings.Join(headers, "\r\n") + htmlBody
	return emailBody, nil
}

func main() {
	// Example usage
	from := "user@example.com"
	to := "support@company.com"
	user := "John Doe"
	subject := "Feature Request"
	content := "I'd like to request a new feature:\n- Dark mode option\n- Export functionality\n\nThanks!"

	email, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println(email)
}

