package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Parse and validate fromAddr and toAddr
	fromAddrParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toAddrParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Format the sender and recipient addresses for the email headers
	formatHeaderAddress := func(addr *mail.Address) string {
		if addr.Name == "" {
			return addr.Address
		}
		// Encode the display name to handle non-ASCII and special characters
		encodedName := mime.QEncoding.Encode("utf-8", addr.Name)
		return fmt.Sprintf("%s <%s>", encodedName, addr.Address)
	}

	fromHeader := formatHeaderAddress(fromAddrParsed)
	toHeader := formatHeaderAddress(toAddrParsed)

	// Prepare the subject for the email
	emailSubject := "Feedback: " + subject
	// Encode the subject to handle non-ASCII and long lines
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Construct email headers
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromHeader,
		toHeader,
		encodedSubject,
	)

	// Escape user input to prevent HTML injection and to safely include in the body
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject) // Note: this is the original subject without prefix
	escapedContent := html.EscapeString(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

