package main

import (
	"fmt"
	"html"
	"mime"
	"strings"
)

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Encode subject for email headers (handles non-ASCII characters)
	encodedSubject := mime.QEncoding.Encode("UTF-8", subject)

	// Escape user inputs for HTML safety
	escapedName := html.EscapeString(userName)
	escapedContent := html.EscapeString(feedbackContent)

	// Convert newlines to <br> tags in feedback content
	escapedContent = strings.Replace(escapedContent, "\n", "<br>", -1)

	// Construct HTML email body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body>
    <h2>User Feedback Submission</h2>
    <p><strong>User Name:</strong> %s</p>
    <p><strong>Subject:</strong> %s</p>
    <p><strong>Feedback Content:</strong></p>
    <div>%s</div>
</body>
</html>`, escapedName, html.EscapeString(subject), escapedContent)

	// Build email headers
	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      encodedSubject,
		"MIME-Version": "1.0",
		"Content-Type": "text/html; charset=\"UTF-8\"",
	}

	// Combine headers and body
	var builder strings.Builder
	for key, value := range headers {
		builder.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	builder.WriteString("\r\n")
	builder.WriteString(htmlBody)

	return builder.String(), nil
}

func main() {
	// Example usage
	email, err := BuildFeedbackEmail(
		"sender@example.com",
		"support@example.com",
		"John Doe",
		"Test Feedback",
		"Hello,\nThis is a test feedback message.\nPlease fix the issue!",
	)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Generated email:")
	fmt.Println(email)
}

