import (
	"encoding/base64"
	"fmt"
	"html"
	"strings"
)

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Encode subject for email header
	encodedSubject := "=?UTF-8?B?" + base64.StdEncoding.EncodeToString([]byte(subject)) + "?="

	// Escape user inputs for HTML body
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Replace newlines with <br> for HTML formatting
	escapedContent = strings.ReplaceAll(escapedContent, "\n", "<br>")

	// Construct email headers
	headers := "From: " + fromAddr + "\r\n" +
		"To: " + toAddr + "\r\n" +
		"Subject: " + encodedSubject + "\r\n" +
		"MIME-Version: 1.0\r\n" +
		"Content-Type: text/html; charset=UTF-8\r\n" +
		"\r\n" // Blank line separating headers and body

	// Construct HTML body
	htmlBody := `<html>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Username:</strong> ` + escapedUserName + `</p>
  <p><strong>Subject:</strong> ` + escapedSubject + `</p>
  <p><strong>Feedback Content:</strong></p>
  <p>` + escapedContent + `</p>
</body>
</html>`

	return headers + htmlBody, nil
}

func main() {
	// Example usage
	emailBody, err := BuildFeedbackEmail(
		"user@example.com",
		"support@company.com",
		"John Doe",
		"Feature Request",
		"I would love to see a dark mode option!\nIt would be easier on my eyes during night usage.",
	)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Println(emailBody)
}

